import { useState, useEffect, useCallback } from 'react';
import { getApiBase } from '../utils/platform';
import GlassPanel from '../components/ui/GlassPanel';
import usePageTitle from '../hooks/usePageTitle';
import s from './MicrostructurePage.module.css';

function ScoreGauge({ score, size = 140 }) {
  const radius = (size - 20) / 2;
  const circumference = radius * Math.PI;
  const pct = Math.min(100, Math.max(0, score));
  const offset = circumference - (pct / 100) * circumference;
  const color = pct >= 70 ? 'var(--color-green, #22C55E)' : pct >= 40 ? 'var(--color-amber, #D29922)' : 'var(--color-red, #EF4444)';

  return (
    <div className={s.gaugeWrap}>
      <svg width={size} height={size / 2 + 20} viewBox={`0 0 ${size} ${size / 2 + 20}`}>
        {/* Background arc */}
        <path
          d={`M 10,${size / 2 + 10} A ${radius},${radius} 0 0 1 ${size - 10},${size / 2 + 10}`}
          fill="none" stroke="var(--color-surface-hover, #1C2128)" strokeWidth="10" strokeLinecap="round"
        />
        {/* Score arc */}
        <path
          d={`M 10,${size / 2 + 10} A ${radius},${radius} 0 0 1 ${size - 10},${size / 2 + 10}`}
          fill="none" stroke={color} strokeWidth="10" strokeLinecap="round"
          strokeDasharray={circumference} strokeDashoffset={offset}
          className={s.gaugeArc}
        />
        {/* Score text */}
        <text x={size / 2} y={size / 2} textAnchor="middle" fill={color}
          fontFamily="var(--font-mono, 'JetBrains Mono', monospace)" fontSize="28" fontWeight="800">
          {Math.round(score)}
        </text>
        <text x={size / 2} y={size / 2 + 18} textAnchor="middle" fill="var(--color-text-secondary, #90A3AF)"
          fontFamily="var(--font-body, 'Plus Jakarta Sans', sans-serif)" fontSize="11">
          LIQUIDITY SCORE
        </text>
      </svg>
    </div>
  );
}

function ToxicityBadge({ toxicity }) {
  const cfg = {
    low:    { color: 'var(--color-green, #22C55E)', raw: '#22C55E' },
    medium: { color: 'var(--color-amber, #D29922)', raw: '#D29922' },
    high:   { color: 'var(--color-red, #EF4444)',   raw: '#EF4444' },
  };
  const c = cfg[toxicity] || cfg.medium;
  return (
    <span
      className={s.toxicityBadge}
      style={{
        background: c.raw + '18',
        border: `1px solid ${c.raw}44`,
        color: c.color,
      }}
    >
      <span className={s.toxicityDot} style={{ background: c.color }} />
      {toxicity || 'unknown'} toxicity
    </span>
  );
}

function MetricCard({ label, value, unit, color, description }) {
  return (
    <GlassPanel className={s.metricCardInner}>
      <div className={s.metricLabel}>{label}</div>
      <div className={s.metricRow}>
        <span className={s.metricValue} style={{ color: color || 'var(--color-text, #E5E7DB)' }}>
          {value ?? '--'}
        </span>
        {unit && <span className={s.metricUnit}>{unit}</span>}
      </div>
      {description && (
        <div className={s.metricDesc}>{description}</div>
      )}
    </GlassPanel>
  );
}

const POPULAR_SYMBOLS = ['AAPL', 'MSFT', 'NVDA', 'AMZN', 'GOOGL', 'META', 'TSLA', 'SPY', 'QQQ', 'BTC'];

export default function MicrostructurePage() {
  usePageTitle('Microstructure');
  const [symbol, setSymbol] = useState('AAPL');
  const [inputValue, setInputValue] = useState('AAPL');
  const [micro, setMicro] = useState(null);
  const [score, setScore] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const fetchData = useCallback(async (sym) => {
    setLoading(true);
    setError(null);
    try {
      const [microRes, scoreRes] = await Promise.allSettled([
        fetch(`${getApiBase()}/microstructure/${sym}`).then(r => r.json()),
        fetch(`${getApiBase()}/microstructure/score/${sym}`).then(r => r.json()),
      ]);
      if (microRes.status === 'fulfilled' && !microRes.value.error) setMicro(microRes.value);
      else setMicro(null);
      if (scoreRes.status === 'fulfilled' && !scoreRes.value.error) setScore(scoreRes.value);
      else setScore(null);
      const err = microRes.value?.error || scoreRes.value?.error;
      if (err) setError(err);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData(symbol);
  }, [symbol, fetchData]);

  const handleSubmit = (e) => {
    e.preventDefault();
    const v = inputValue.trim().toUpperCase();
    if (v) setSymbol(v);
  };

  const fmt = (val, dec = 4) => val != null ? Number(val).toFixed(dec) : '--';
  const fmtBps = (val) => val != null ? `${Number(val).toFixed(1)} bps` : '--';

  const metrics = micro ? [
    { label: 'Bid-Ask Spread', value: fmtBps(micro.bid_ask_spread_bps), color: 'var(--color-blue, #60A5FA)', desc: 'Quoted bid-ask spread in basis points' },
    { label: 'Effective Spread', value: fmtBps(micro.effective_spread_bps), color: 'var(--color-blue, #60A5FA)', desc: 'Realized execution spread' },
    { label: 'Realized Vol (5m)', value: fmt(micro.realized_volatility_5m, 4), color: 'var(--color-amber, #D29922)', desc: '5-minute realized volatility' },
    { label: 'Volume Imbalance', value: fmt(micro.volume_imbalance, 3), color: micro.volume_imbalance > 0 ? 'var(--color-green, #22C55E)' : 'var(--color-red, #EF4444)', desc: 'Buy vs sell volume ratio' },
    { label: 'Price Impact', value: fmtBps(micro.price_impact_bps), color: 'var(--color-red, #EF4444)', desc: 'Estimated price impact per trade' },
    { label: "Kyle's Lambda", value: fmt(micro.kyle_lambda, 6), color: 'var(--color-purple, #BC8CFF)', desc: 'Price impact coefficient' },
    { label: 'Amihud Illiquidity', value: fmt(micro.amihud_illiquidity, 6), color: 'var(--color-amber, #D29922)', desc: 'Price response to volume' },
    { label: 'Roll Spread', value: fmt(micro.roll_spread, 4), color: 'var(--color-blue, #60A5FA)', desc: 'Roll implicit spread estimate' },
    { label: 'VPIN', value: fmt(micro.vpin, 4), color: 'var(--color-red, #EF4444)', desc: 'Volume-synchronized probability of informed trading' },
    { label: 'Order Flow Toxicity', value: fmt(micro.order_flow_toxicity, 4), color: 'var(--color-red, #EF4444)', desc: 'Adverse selection risk' },
  ] : [];

  return (
    <div className={s.pageRoot}>
      <h1 className={s.title}>Microstructure Analysis</h1>
      <p className={s.subtitle}>
        Liquidity scoring, toxicity classification, and market microstructure metrics
      </p>

      {/* Symbol selector */}
      <div className={s.symbolSelector}>
        <form onSubmit={handleSubmit} className={s.searchForm}>
          <input
            value={inputValue}
            onChange={e => setInputValue(e.target.value.toUpperCase())}
            placeholder="Enter symbol..."
            className={s.symbolInput}
          />
          <button type="submit" disabled={loading} className={s.analyzeBtn}>
            {loading ? 'Loading...' : 'Analyze'}
          </button>
        </form>
        <div className={s.symbolChips}>
          {POPULAR_SYMBOLS.map(sym => (
            <button
              key={sym}
              onClick={() => { setInputValue(sym); setSymbol(sym); }}
              className={s.symbolChip}
              style={{
                background: symbol === sym ? 'rgba(96,165,250,0.13)' : 'var(--color-surface-hover, #1C2128)',
                border: `1px solid ${symbol === sym ? 'var(--color-blue, #60A5FA)' : 'var(--color-border, #1F2A37)'}`,
                color: symbol === sym ? 'var(--color-blue, #60A5FA)' : 'var(--color-text-secondary, #90A3AF)',
              }}
            >
              {sym}
            </button>
          ))}
        </div>
      </div>

      {error && (
        <GlassPanel className={s.errorPanel}>
          <div className={s.errorText}>{error}</div>
        </GlassPanel>
      )}

      {loading && (
        <div className={s.loadingState}>
          Analyzing {symbol} microstructure...
        </div>
      )}

      {!loading && (micro || score) && (
        <>
          {/* Score + Toxicity header */}
          <div className={s.scoreHeader}>
            {score && (
              <GlassPanel className={s.scorePanel}>
                <ScoreGauge score={score.liquidity_score || 0} />
                <div>
                  <div className={s.symbolName}>{symbol}</div>
                  <ToxicityBadge toxicity={score.toxicity} />
                  <div className={s.scoreMeta}>
                    Spread: {fmtBps(score.spread_bps)} | Amihud: {fmt(score.amihud, 6)}
                  </div>
                </div>
              </GlassPanel>
            )}
          </div>

          {/* Metrics grid */}
          {metrics.length > 0 && (
            <div className={s.metricsGrid}>
              {metrics.map(m => (
                <MetricCard key={m.label} label={m.label} value={m.value} color={m.color} description={m.desc} />
              ))}
            </div>
          )}
        </>
      )}

      {!loading && !micro && !score && !error && (
        <GlassPanel className={s.emptyPanel}>
          <div className={s.emptyText}>Enter a symbol to analyze its microstructure</div>
        </GlassPanel>
      )}
    </div>
  );
}
